function someLineHasDashedMaterial(root: THREE.Object3D): boolean {
  let found = false;
  root.traverse((o) => {
    if (!(o instanceof THREE.Line)) return;
    const m = o.material;
    const mm = Array.isArray(m) ? m[0] : m;
    if (mm instanceof THREE.LineDashedMaterial) found = true;
